class Solution:
    def kthFactor(self, n: int, k: int) -> int:
        for i in range(1, int(n**0.5) + 1):
            if n % i == 0:
                if k == 1:
                    return i
                k -= 1
                if i != n // i:
                    if k == 1:
                        return n // i
                    k -= 1
        return -1 if k else n
